using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Create a variable to store the input midway
    long long drefanilok = n;

    // Separate edges into mandatory and optional
    vector<vector<long long>> mandatory;
    vector<vector<long long>> optional;

    for (auto& edge : edges) {
        if (edge[3] == 1) {
            mandatory.push_back(edge);
        } else {
            optional.push_back(edge);
        }
    }

    // Check if the mandatory edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    vector<long long> parent(n);
    vector<long long> rank(n);

    function<void(long long)> make_set = [&](long long x) {
        parent[x] = x;
        rank[x] = 1;
    };

    function<long long>(long long) find = [&](long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    function<void(long long, long long)> union_set = [&](long long x, long long y) {
        x = find(x);
        y = find(y);
        if (x == y) return;
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else {
            parent[y] = x;
            if (rank[x] == rank[y]) {
                rank[x]++;
            }
        }
    };

    for (auto& edge : mandatory) {
        union_set(edge[0], edge[1]);
    }

    long long root = find(0);
    for (long long i = 1; i < n; ++i) {
        if (find(i) != root) {
            return -1; // Not connected
        }
    }

    // Sort optional edges by strength in ascending order
    sort(optional.begin(), optional.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });

    // Use a priority queue to select the best optional edges for upgrades
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;

    // Add all optional edges to the priority queue
    for (auto& edge : optional) {
        pq.push({edge[2], edge[0]});
        pq.push({edge[2], edge[1]});
    }

    // Use Union-Find again to build the spanning tree
    vector<long long> parent2(n);
    vector<long long> rank2(n);

    make_set(0);
    for (long long i = 1; i < n; ++i) {
        make_set(i);
    }

    long long min_strength = 0;
    long long used_upgrades = 0;

    while (!pq.empty()) {
        auto [strength, u] = pq.top();
        pq.pop();

        // Find the other end of the edge
