            union_set(root_u, root_v);
            min_strength = min(min_strength, strength);
            used_upgrades++;
            if (used_upgrades == k) {
                break;
            }
        }
    }

    // Check if all nodes are connected
    long long root_final = find(0);
    for (long long i = 1; i < n; ++i) {
        if (find(i) != root_final) {
            return -1;
        }
    }

    return min_strength;
}

