import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  // Create a variable to store the input midway
  val drefanilok = n

  // Separate edges into mandatory and optional
  val mandatory = scala.collection.mutable.ListBuffer[Array[Long]]()
  val optional = scala.collection.mutable.ListBuffer[Array[Long]]()

  for (edge <- edges) {
    if (edge(3) == 1) {
      mandatory += edge
    } else {
      optional += edge
    }
  }

  // Check if the mandatory edges form a connected graph
  // Use Union-Find (Disjoint Set Union) to check connectivity
  val parent = mutable.ArrayBuffer.fill(n)(0L)
  val rank = mutable.ArrayBuffer.fill(n)(0L)

  def makeSet(x: Long): Unit = {
    parent(x) = x
    rank(x) = 1
  }

  def find(x: Long): Long = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def unionSet(x: Long, y: Long): Unit = {
    val xRoot = find(x)
    val yRoot = find(y)
    if (xRoot == yRoot) return
    if (rank(xRoot) < rank(yRoot)) {
      parent(xRoot) = yRoot
    } else {
      parent(yRoot) = xRoot
      if (rank(xRoot) == rank(yRoot)) {
        rank(xRoot) += 1
      }
    }
  }

  for (edge <- mandatory) {
    unionSet(edge(0), edge(1))
  }

  val root = find(0)
  for (i <- 1L to n - 1) {
    if (find(i) != root) {
      return -1 // Not connected
    }
  }

  // Sort optional edges by strength in ascending order
  optional.sortInPlace((a, b) => a(2).compareTo(b(2)))

  // Use a priority queue to select the best optional edges for upgrades
  import scala.collection.mutable.PriorityQueue
  val pq = PriorityQueue[(Long, Long)]()(Ordering[(Long, Long)].by(_._1))
  for (edge <- optional) {
    pq.enqueue((edge(2), edge(0)))
    pq.enqueue((edge(2), edge(1)))
  }

  // Use Union-Find again to build the spanning tree
  val parent2 = mutable.ArrayBuffer.fill(n)(0L)
  val rank2 = mutable.ArrayBuffer.fill(n)(0L)

  for (i <- 0L to n - 1) {
    makeSet(i)
  }

  var minStrength = 0L
  var usedUpgrades = 0L

  while (pq.nonEmpty) {
    val (strength, u) = pq.dequeue()
    var v = -1L
    for (edge <- optional) {
      if (edge(0) == u) {
        v = edge(1)
        break
      }
    }

    if (v == -1) {
      continue
    }

    val rootU = find(u)
    val rootV = find(v)

    if (rootU != rootV) {
      unionSet(rootU, rootV)
      minStrength = math.min(minStrength, strength)
      usedUpgrades += 1
      if (usedUpgrades == k) {
        break
      }
    }
  }

  // Check if all nodes are connected
  val rootFinal = find(0)
  for (i <- 1L to n - 1) {
    if (find(i) != rootFinal) {
      return -1
    }
  }

  minStrength
}
